import{_ as l,o as i,c as e,a2 as t}from"./chunks/framework.LN3EJxkW.js";const m=JSON.parse('{"title":"每日 AI 实验","description":"","frontmatter":{},"headers":[],"relativePath":"04-ai/daily/README.md","filePath":"04-ai/daily/README.md","lastUpdated":1784212366000}'),o={name:"04-ai/daily/README.md"};function r(n,a,d,h,s,c){return i(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="每日-ai-实验" tabindex="-1">每日 AI 实验 <a class="header-anchor" href="#每日-ai-实验" aria-label="Permalink to &quot;每日 AI 实验&quot;">​</a></h1><p>AI 侧每天做一个“小型能力验证”，而不是只追新闻或收藏工具。固定任务和评测样例，每次只改变一个变量，才可能看见模型、Prompt、Context、RAG、Tool 或 Workflow 的真实差异。</p><h2 id="实验题目" tabindex="-1">实验题目 <a class="header-anchor" href="#实验题目" aria-label="Permalink to &quot;实验题目&quot;">​</a></h2><ul><li>Prompt：指令结构、示例、约束、输出格式和失败行为。</li><li>Model/API：结构化输出、Streaming、多模态、Token 与上下文限制。</li><li>Context：选择、排序、压缩、记忆、冲突和权限。</li><li>RAG：解析、Chunk、查询、召回、重排、引用和无答案。</li><li>Tool/MCP：Schema、工具选择、参数、确认、幂等和错误恢复。</li><li>Workflow/Agent：路由、并行、计划、停止、恢复和任务完成率。</li><li>Evaluation/Safety：Grader、回归样例、注入、越权、隐私和成本攻击。</li></ul><h2 id="建议节奏" tabindex="-1">建议节奏 <a class="header-anchor" href="#建议节奏" aria-label="Permalink to &quot;建议节奏&quot;">​</a></h2><ul><li>周一：模型 API 或 Prompt。</li><li>周二：Context 或 RAG。</li><li>周三：Tool、MCP 或 Workflow。</li><li>周四：Evaluation、Observability 或 Safety。</li><li>周五：复测一个新模型/版本或拆解一个真实 AI 产品能力。</li></ul><p>节奏只是选题辅助，不要求为了打卡每天切换主题。</p><h2 id="记录方式" tabindex="-1">记录方式 <a class="header-anchor" href="#记录方式" aria-label="Permalink to &quot;记录方式&quot;">​</a></h2><ol><li>复制 <a href="./_template">_template.md</a>。</li><li>按 <code>YYYY/MM/YYYY-MM-DD-hypothesis.md</code> 保存。</li><li>评测样例和脚本放在记录的同名目录；密钥、敏感输入和完整用户数据禁止提交。</li><li>模型或框架升级时复跑旧实验，把结果链接到原记录，形成纵向比较。</li></ol><h2 id="完成标准" tabindex="-1">完成标准 <a class="header-anchor" href="#完成标准" aria-label="Permalink to &quot;完成标准&quot;">​</a></h2><ul><li>[ ] 有明确假设、固定样例、变量和基线。</li><li>[ ] 记录完整模型标识、版本、日期和关键参数。</li><li>[ ] 同时观察质量、延迟、Token、成本和失败类型。</li><li>[ ] 结论可复现、可证伪，并说明适用边界。</li></ul>',11)])])}const _=l(o,[["render",r]]);export{m as __pageData,_ as default};
